CREATE OR REPLACE FUNCTION safe_div(n NUMERIC, d NUMERIC) RETURNS NUMERIC AS $$
BEGIN
    IF d = 0 OR d IS NULL THEN RETURN 0; END IF;
    RETURN n / d;
END;
